mapper.select:
/* wms-outbound-order-cancel-sql-oracle.xml - selectOutboundHeaderList - S.O주문번호 / 고객주문번호에 해당하는 릴리즈코드 내역 조회 */
SELECT
	CTKEY
	,OWKEY
	,OBHDKEY
	,#{cnlrsncd} AS CNLRSNCD
	,#{cnlrsn} AS CNLRSN
FROM TWORK_INFO_OB_HD
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND ORHDKEY = #{orhdkey}

AND EXTERNORDERKEY = #{externorderkey}

/* wms-outbound-order-cancel-sql-oracle.xml - selectOutboundDetailList - 릴리즈 상세 정보 조회 */
SELECT
	CTKEY
	,OWKEY
	,OBHDKEY
	,OBDTKEY
	,ALQTY
FROM TWORK_INFO_OB_DT
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBHDKEY = #{obhdkey}

mapper.delete:
/* wms-outbound-order-cancel-sql-oracle.xml - deleteWaveDetailByOutboundHeaderKey - WAHDKEY 존재 시 WA_DT 제거 */
DELETE FROM TWORK_INFO_WA_DT
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND WAHDKEY = #{wahdkey}
AND OBHDKEY = #{obhdkey}

mapper.update:
/* wms-outbound-order-cancel-sql-oracle.xml - updateOutboundDetailCancel - 릴리즈 상세 정보 주문취소 처리 */
UPDATE TWORK_INFO_OB_DT
SET OBDTSTATUSCD = '99'
	, UPDATEDATE = #{sysdate}
	, UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBHDKEY = #{obhdkey}
AND OBDTKEY = #{obdtkey}

/* wms-outbound-order-cancel-sql-oracle.xml - updateOutboundHeaderCancel - 릴리즈 헤더 정보 주문취소 처리 */
UPDATE TWORK_INFO_OB_HD
SET OBSTATUSCD = '99'
	, WAHDKEY = NULL
	, DASSTNBARCODE = NULL
	, CNLRSNCD = #{cnlrsncd}
	, CNLRSN = #{cnlrsn}
	, UPDATEDATE = #{sysdate}
	, UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBHDKEY = #{obhdkey}

/* wms-outbound-order-cancel-sql-oracle.xml - updateOutboundOrderHeaderCancel - 출고주문 헤더 정보 주문취소 처리 */
UPDATE TWORK_INFO_OB_ORD_HD
SET CNLRSNCD = #{cnlrsncd}
	, CNLRSN = #{cnlrsn}
	, UPDATEDATE = #{sysdate}
	, UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND ORHDKEY = #{orhdkey}

AND EXTERNORDERKEY = #{externorderkey}

/* wms-outbound-order-cancel-sql-oracle.xml - updateObHdRcv - 주문취소 요청시 인터페이스 테이블에 취소정보 저장 */
UPDATE TWORK_INTF_OB_HD_RCV
   SET CNLRSNYN = 'Y' /*취소요청여부*/
   	 , CNLRSNCD = #{cnlrsncd} /*취소사유코드*/
	 , CNLRSN = #{cnlrsn} /*취소사유*/
	 , CNLRSNDATE = #{sysdate} /*취소요청시간*/
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND SOHDKEY = #{orhdkey}

   AND EXTERNORDERKEY = #{externorderkey}
